INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-6f0ba476-moex-00864', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-01c5eaab', 'sub-elementary-6f0ba476-05', NULL, 'single_choice', '「鳥飛到雲中去／鳥群中少了你／太陽落到山稜後／山群中少了你／是的，少了你這風景又怎能印得成記 憶」，下列何者最接近本詩旨意？', '["繁華落盡見真淳", "鳥盡良弓勢必藏", "有了你，生命才有意義", "有遺憾，也是一種美麗"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00865', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-01c5eaab', 'sub-elementary-6f0ba476-05', NULL, 'single_choice', '陳述古密直知建州浦城縣日，有人失物，捕得，莫知的為盜者。述古乃紿之曰：「某廟有一鐘，能辨盜至靈。」 使人迎置後閤祠之，引群囚立鐘前，自陳：不為盜者摸之則無聲，為盜者摸之則有聲。述古自率同職禱鐘甚 肅，祭訖，以帷圍之，乃陰使人以墨塗鐘。良久，引囚逐一令引手入帷摸之，出乃驗其手，皆有墨，唯有一 囚無墨。訊之，遂承為盜，蓋恐鐘有聲，不敢摸也（沈括《夢溪筆談》）。文中「述古自率同職禱鐘甚肅」 的主要用意為何？', '["假借鬼神之說，使人心生畏懼", "善用辦案工具，期能事半功倍", "官府例行公事，以求辦案順利", "藉由虔誠敬拜，祈求鬼神助佑"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00866', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-01c5eaab', 'sub-elementary-6f0ba476-05', NULL, 'single_choice', '「我的朋友是一位肖像畫家，生活不好過，朋友紛紛給她忠告。大多數人的建議歸結來講就是：『找份正職 吧。』她對我說：『我本來就有正職啊！我是個畫家，他們難道不明白嗎？』……三年過去了，到目前為止， 我的朋友證明了自己是對的。」下列何者，最符合文意？', '["藝術家可以將個人創作視為正職", "創作與謀生彼此衝突而不能兼顧", "藝術無價不必討論現實薪資問題", "有固定收入才是藝術家謀生之道"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00867', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-01c5eaab', 'sub-elementary-6f0ba476-05', NULL, 'single_choice', '「古人有詩云：『但願此心春長在，須知世上苦人多。』若能時時想到世間多少不如我們、需要我們幫助的 人，那麼成敗得失之念，就容納不下，此心就充滿歡樂了。」下列選項，最接近意旨的是：', '["知足常樂", "簡單就是快樂", "寬容是快樂的來源", "獨樂樂，不如眾樂樂"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00868', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-01c5eaab', 'sub-elementary-6f0ba476-05', NULL, 'single_choice', '「身為埔里農家小子，年輕的洪健智不想待在故鄉務農，高中畢業後便毅然前往臺北晶華飯店學習和式料 理。在緊湊的都會生活裡，他圓了夢，卻也因此錯失了孩子部分的成長時光。『週遭長輩都會說，要讓孩子 在都市成長，才會有競爭力。結果卻是讓孩子的童年只剩學校和安親班。』洪健智談起孩子，回想自己，『我 們小時候在田野裡跑啊跑啊，在溪邊釣魚、原野上焢窯，那才是真的快樂的小時候！』」根據上文，下列選 項何者最符合本文意旨？', '["相較城市生活，家鄉生活步調更適合自己", "競爭力並非一定要在城市才可以培養出來", "童年的時光很重要，希望將快樂還給孩子", "對於年少時期的錯誤選擇，感到後悔不已"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00869', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-01c5eaab', 'sub-elementary-6f0ba476-05', NULL, 'single_choice', '「如膠似漆」與「水乳交融」語意對應關係，與下列何組最不相同？', '["「宵衣旰食」與「廢寢忘餐」", "「推心置腹」與「披肝瀝膽」", "「弊絕風清」與「政以賄成」", "「巾幗鬚眉」與「女中豪傑」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00870', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-01c5eaab', 'sub-elementary-6f0ba476-05', NULL, 'single_choice', '「素養跟知識有沒有差別？當然有，而且有著極其關鍵的差別。我們不要忘記，納粹頭子很多會彈鋼琴、有 哲學博士學位。」下列選項，最接近意旨的是：', '["知識易使人傲慢", "讀書越多，精神就越健康而勇敢", "才能只是天分，善良卻是一種選擇", "不要用華麗外衣裝飾，而是以知識武裝自己"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00871', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-01c5eaab', 'sub-elementary-6f0ba476-05', NULL, 'single_choice', '下列選項，何者表達出「壯志猶存」的懷抱？', '["人生得意須盡歡，莫使金樽空對月", "今朝有酒今朝醉，明日愁來明日愁", "人生到處知何似，應似飛鴻踏雪泥", "夜闌臥聽風吹雨，鐵馬冰河入夢來"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00872', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-01c5eaab', 'sub-elementary-6f0ba476-05', NULL, 'single_choice', '在公文中稱受文者為「鈞部」，可知發文者為：', '["有隸屬關係的上級機關", "有隸屬關係的下級機關", "無隸屬關係的上級機關", "無隸屬關係的下級機關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00873', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-01c5eaab', 'sub-elementary-6f0ba476-05', NULL, 'single_choice', '有關公文稱謂用語，下列正確的選項是：', '["大學發函給校友，自稱本校，稱對方為臺端", "教育部發函各大學，自稱鈞部，稱對方為貴校", "小華旅日請外交部提供協助，自稱本人，稱對方為大部", "臺中市中小學發函給臺中市政府教育局，自稱職，稱對方為鈞府"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL)
